#[derive(Debug, Clone)]
pub(crate) struct ExtensionImplMethod {
    self_ty: syn::Type,
    method: syn::ImplItemFn,
    callable_param_metadata: HashMap<String, CallableParamBoundMetadata>,
    associated_type_bindings: HashMap<String, syn::Type>,
    /// Impl-level generic type parameter names from the surrounding
    /// `impl<Idx, T, ...>`. Used by the Adapter spec emitter to detect
    /// generic impls (which need partial specializations) and skip them.
    impl_generic_names: Vec<String>,
    /// UFCS Fix A part 2 (§ 3.2.4): an extra `requires`-clause to inject after
    /// the template parameter list — used to CONSTRAIN a multi-owner default
    /// method's template (`requires requires(const Self_& s){ Tr_::__ufcs_impls(s); }`)
    /// so it matches only types implementing that trait. `None` for ordinary
    /// methods.
    extra_template_requires: Option<String>,
    /// True for a trait DEFAULT method (book § 3.2.13): `self_ty` is the bare
    /// `Self`, which must be emitted as a leading template parameter
    /// (`template <class Self> … (const Self& self_, …)`) rather than a concrete
    /// receiver type. When set, the emitter prepends `class Self` to the
    /// template header and skips the `using Self = decltype(self_);` alias
    /// (which would be the ill-formed `using Self = Self;`).
    self_is_template_param: bool,
}

/// Storage shape for a `--interface-traits` Adapter specialization.
/// Determines the `value_` field type, the constructor signature, and
/// whether `&mut self` trait methods can be delegated through the
/// stored handle. See § 3.2.9 of `docs/rusty-cpp-transpiler.md`.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum AdapterStorageKind {
    /// Holds U by value. Used for `Box<dyn T>` / `Rc<dyn T>` / `Arc<dyn T>`.
    Owning,
    /// Holds `const U&`. Used for `&dyn T`. &mut self overrides are
    /// emitted as unreachable bodies (C++ const-correctness forbids
    /// reaching them through a `const TraitName&`).
    ConstRef,
    /// Holds `U&`. Used for `&mut dyn T`. Both &self and &mut self
    /// overrides delegate normally.
    MutRef,
}

