    fn alias_expansion_looks_self_wrapping(prev: &syn::Type, next: &syn::Type) -> bool {
        let (syn::Type::Path(prev_tp), syn::Type::Path(next_tp)) = (prev, next) else {
            return false;
        };
        if prev_tp.qself.is_some() || next_tp.qself.is_some() {
            return false;
        }
        let prev_head = prev_tp
            .path
            .segments
            .first()
            .map(|seg| seg.ident.to_string());
        let prev_tail = prev_tp
            .path
            .segments
            .last()
            .map(|seg| seg.ident.to_string());
        let next_head = next_tp
            .path
            .segments
            .first()
            .map(|seg| seg.ident.to_string());
        let next_tail = next_tp
            .path
            .segments
            .last()
            .map(|seg| seg.ident.to_string());
        if prev_head != next_head || prev_tail != next_tail {
            return false;
        }
        let prev_shape = prev.to_token_stream().to_string();
        let next_shape = next.to_token_stream().to_string();
        next_shape.len() > prev_shape.len() && next_shape.contains(&prev_shape)
    }



    fn struct_member_name_conflicts_with_method(
        &self,
        struct_name: &str,
        member_name: &str,
    ) -> bool {
        let struct_tail = struct_name.rsplit("::").next().unwrap_or(struct_name);
        self.inherent_impl_method_names
            .iter()
            .any(|(impl_ty, methods)| {
                if !methods.contains(member_name) {
                    return false;
                }
                let impl_tail = impl_ty.rsplit("::").next().unwrap_or(impl_ty.as_str());
                impl_ty == struct_name
                    || impl_tail == struct_tail
                    || impl_ty.ends_with(&format!("::{}", struct_tail))
                    || struct_name.ends_with(&format!("::{}", impl_tail))
            })
    }

    fn expected_type_matches_struct_literal_path(
        &self,
        expected_ty: &syn::Type,
        struct_path: &syn::Path,
    ) -> bool {
        let expected_path = match expected_ty {
            syn::Type::Path(tp) => &tp.path,
            syn::Type::Reference(r) => {
                return self.expected_type_matches_struct_literal_path(&r.elem, struct_path);
            }
            syn::Type::Paren(p) => {
                return self.expected_type_matches_struct_literal_path(&p.elem, struct_path);
            }
            syn::Type::Group(g) => {
                return self.expected_type_matches_struct_literal_path(&g.elem, struct_path);
            }
            _ => return false,
        };
        let Some(expected_last) = expected_path.segments.last() else {
            return false;
        };
        let Some(struct_last) = struct_path.segments.last() else {
            return false;
        };
        if expected_last.ident == struct_last.ident {
            return true;
        }
        if expected_last.ident == "Self" {
            if let Some(current_struct) = &self.current_struct {
                return current_struct == &struct_last.ident.to_string();
            }
        }
        false
    }


